/* === PWM 驱动抽象层接口定义 === */

typedef struct {
    HRTIM_TypeDef *hrtim;       /* HRTIM 外设基址 */
    uint8_t         channel;     /* PWM 通道编号 (1-4) */
    uint32_t        period;      /* ARR 寄存器值 */
    volatile uint16_t duty;      /* 当前占空比 (CMPx 值) */
} pwm_driver_t;

/* 初始化 PWM 通道 —— 配置 HRTIM 模式、GPIO 复用、死区 */
pwm_err_t pwm_init(pwm_driver_t *pwm, HRTIM_TypeDef *h, uint8_t ch,
                   uint32_t freq_hz, uint16_t deadtime_us);

/* 设置 PWM 频率 —— 更新 ARR 寄存器并重载影子寄存器 */
pwm_err_t pwm_set_frequency(pwm_driver_t *pwm, uint32_t freq_hz);

/* 设置占空比 0-1000 (0.1% 精度) —— 更新 CMPx 寄存器 */
pwm_err_t pwm_set_duty_cycle(pwm_driver_t *pwm, uint16_t duty_x10);

/* 立即关闭 PWM 输出 —— 置位 OFFx 寄存器 */
void pwm_force_off(pwm_driver_t *pwm);

/* === STM32G4 HRTIM 三相 PWM 配置（20kHz + 200ns 死区）=== */
#define HRTIM_FREQ_MHZ    170   /* HRTIM 时钟 = 170 MHz */
#define PWM_FREQ_KHZ      20    /* PWM 频率 = 20 kHz */
#define DEADTIME_NS       200   /* 死区时间 = 200 ns */

static HRTIM_TimeBaseCfg_t tb_cfg;
static HRTIM_PWMCfg_t      pwm_cfg;
static HRTIM_CompareCfg_t  cmp_cfg;

void hrtim_motor_pwm_init(void) {
    /* 步骤 1: 配置时基 —— ARR=1055, 8 位重装载, 上升沿更新 */
    tb_cfg.PrescalerRatio    = HRTIM_PRESCALERRATIO_MUL8;
    tb_cfg.Mode              = HRTIM_MODE_CONTINUOUS;
    tb_cfg.Period            = 1055;  /* 170MHz/8/20kHz - 1 */
    tb_cfg.RepetitionCounter = 0;
    tb_cfg.ClearOutputOnTimebaseClearEvent = DISABLE;
    HAL_HRTIM_TimeBaseCfg(&hhrtim1, HRTIM_TIMERINDEX_TIMER_A, &tb_cfg);

    /* 步骤 2: 配置死区 —— 200ns / 6.25ns = 32 ticks */
    HRTIM_DeadTimeCfg_t dt;
    dt.PrescalerRatio = HRTIM_DTPRESCALER_MUL1;
    dt.RisingValue    = 32;  /* 200ns 上升沿死区 */
    dt.FallingValue   = 32;  /* 200ns 下降沿死区 */
    dt.Lock           = HRTIM_LOCK_18_32BITS;
    dt.Output1Level   = HRTIM_OUTPUT1_SET;  /* 死区内输出高 */
    dt.Output2Level   = HRTIM_OUTPUT2_RESET;
    dt.Out3Level      = HRTIM_OUTPUT3_FLOATING;
    dt.Out4Level      = HRTIM_OUTPUT4_FLOATING;
    dt.Out5Level      = HRTIM_OUTPUT5_FLOATING;
    dt.Out6Level      = HRTIM_OUTPUT6_FLOATING;
    dt.InvertedOutput = HRTIM_OUTPUTINVERTED_GPIO;
    dt.FaultStatus    = HRTIM_FAULT_PFMENABLE;
    HAL_HRTIM_ConfigDeadTime(&hhrtim1, HRTIM_TIMERINDEX_TIMER_A, &dt);

    /* 步骤 3: 配置比较寄存器 —— CMP1=0 (初始 0% 占空比) */
    cmp_cfg.CompareValue = 0;
    HAL_HRTIM_ConfigCompare(&hhrtim1, HRTIM_TIMERINDEX_TIMER_A,
                            HRTIM_COMPAREUNIT_1, &cmp_cfg);

    /* 步骤 4: 配置 PWM 模式 —— 模式 1 (中央对齐) */
    pwm_cfg.Mode      = HRTIM_PWM_MODE_SYNCHRONIZED;
    pwm_cfg.PulseMode = HRTIM_OUTPUT_SETPULSEONCOMPARE1;
    pwm_cfg.Polarity  = HRTIM_OUTPUTPOLARITY_NONINVERTED;
    pwm_cfg.SetPulseOnCompareEvent = HRTIM_SETTRIGGERSOURCE_0;
    pwm_cfg.ClearPulseOnCompareEvent = HRTIM_CLEARTRGSOURCE_0;
    HAL_HRTIM_ConfigOutput(&hhrtim1, HRTIM_TIMERINDEX_TIMER_A,
                           HRTIM_OUTPUT_TAOUT1, &pwm_cfg);
    HAL_HRTIM_ConfigOutput(&hhrtim1, HRTIM_TIMERINDEX_TIMER_A,
                           HRTIM_OUTPUT_TAOUT2, &pwm_cfg);

    /* 步骤 5: 使能定时器 A */
    HAL_HRTIM_WaveformCounterStart(&hhrtim1, HRTIM_TIMERMASK_TIMER_A);
    HAL_HRTIM_WaveformOutputStart(&hhrtim1,
        HRTIM_OUTPUTSET_TAOUT1 | HRTIM_OUTPUTSET_TAOUT2);
}

/* === 陷阱演示：影子寄存器重载的正确顺序 === */

/* ❌ 错误做法 —— 直接写 CMPx，不触发影子重载 */
void bad_duty_change(pwm_driver_t *pwm, uint16_t new_duty) {
    /* 直接写入比较寄存器 —— 立即生效，可能产生毛刺 */
    pwm->hrtim->CCR[pwm->channel] = new_duty;
    /* 没有预装载位，没有影子重载 —— 下一个周期立即突变 */
}

/* ✅ 正确做法 —— 预装载 + 影子寄存器重载 */
pwm_err_t good_duty_change(pwm_driver_t *pwm, uint16_t new_duty) {
    /* 步骤 1: 写入预装载寄存器（不立即生效）*/
    pwm->hrtim->CMPxPRELOAD[pwm->channel] = new_duty;
    /* 步骤 2: 置位预装载使能位 */
    pwm->hrtim->MCRR |= HRTIM_MCRR_PRELOAD_EN;
    /* 步骤 3: 触发影子寄存器重载（在下一个更新事件边界）*/
    pwm->hrtim->MCR |= HRTIM_MCR_UPD_G;  /* Global Update */
    /* 步骤 4: 验证重载完成 */
    uint32_t timeout = 1000;
    while (!(pwm->hrtim->MISR & HRTIM_MISR_RELOAD) && timeout--) {
        /* 等待硬件确认重载完成 */
    }
    if (timeout == 0) return PWM_ERR_TIMEOUT;
    pwm->duty = new_duty;
    return PWM_OK;
}

/* === 重构前：裸机轮询 PWM 控制（main 循环阻塞）=== */
void main_loop(void) {
    while (1) {
        /* 读 ADC 通道 1 —— 阻塞等待转换完成 */
        HAL_ADC_Start(&hadc1);
        HAL_ADC_PollForConversion(&hadc1, 10);
        float voltage = HAL_ADC_GetValue(&hadc1) * 3.3f / 4096.0f;

        /* PID 计算 —— 浮点运算，无 FPU 时很慢 */
        float error = SETPOINT_V - voltage;
        integral += error * 0.0001f;       /* 100us 积分步长 */
        derivative = (error - prev_error) / 0.0001f;
        float output = Kp * error + Ki * integral + Kd * derivative;
        prev_error = error;

        /* 限幅 */
        if (output > MAX_DUTY) output = MAX_DUTY;
        if (output < MIN_DUTY) output = MIN_DUTY;

        /* 写 PWM 占空比 —— 直接操作寄存器 */
        TIM2->CCR1 = (uint32_t)(output * TIM2->ARR);

        /* 延时 100us —— 用循环计数，精度极差 */
        for (volatile int i = 0; i < 1700; i++);
    }
}

/* === 重构后：中断驱动 + DMA + PID 控制 === */

/* 第一步：定义控制环路上下文（静态分配，零动态内存）*/
typedef struct {
    float setpoint;          /* 目标电压 */
    float integral;          /* 积分累加 */
    float prev_error;        /* 上次误差 */
    float duty_x1000;        /* 占空比 (0-1000) */
} pid_context_t;

static pid_context_t pid_ctx;
static volatile float adc_buffer[2];  /* DMA 双缓冲 */
static volatile uint8_t adc_ready = 0;

/* 第二步：PID 计算函数 —— 纯函数，只读输入，不碰硬件 */
static float pid_compute(pid_context_t *ctx, float measured) {
    float error = ctx->setpoint - measured;
    ctx->integral += error * CONTROL_PERIOD_US;  /* 100us */
    float derivative = (error - ctx->prev_error) / CONTROL_PERIOD_US;
    float output = Kp * error + Ki * ctx->integral + Kd * derivative;
    ctx->prev_error = error;

    /* 积分饱和保护（anti-windup）*/
    if (output > MAX_DUTY) { output = MAX_DUTY; ctx->integral -= error * 10; }
    if (output < MIN_DUTY) { output = MIN_DUTY; ctx->integral += error * 10; }
    return output;
}

/* 第三步：HRTIM 更新中断回调 —— 精确触发 PID 控制 */
void HAL_HRTIM_TIMUpdateCallback(HRTIM_HandleTypeDef *hhrtim,
                                  uint32_t TimMaster) {
    /* 只在 Timer A 触发时处理（三相 PWM 的第一相）*/
    if (TimMaster == HRTIM_TIMUPDATE_TIMER_A) {
        /* 等待 ADC DMA 数据就绪 */
        if (adc_ready) {
            float voltage = adc_buffer[0];  /* 最新采样值 */
            float output = pid_compute(&pid_ctx, voltage);
            /* 写入 HRTIM 比较寄存器（影子模式，自动重载）*/
            hhrtim1.Instance->CMPxPRELOAD[HRTIM_COMPAREUNIT_1] =
                (uint32_t)(output * 1000.0f);
        }
    }
}
